import { Component } from '@angular/core';
import { Router } from '@angular/router';

@Component({
  selector: 'app-layout',
  templateUrl: './layout.component.html',
  styleUrls: ['./layout.component.css']
})
export class LayoutComponent {
  constructor(private router: Router) {}

  isActive(route: string): boolean {
    return this.router.isActive(route, {
      paths: 'exact',
      queryParams: 'exact',
      fragment: 'ignored',
      matrixParams: 'ignored'
    });
  }

  scrollToTop() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }
}
<div class="min-h-screen flex flex-col">
  <header class="bg-white shadow-sm sticky top-0 z-50">
    <nav class="container flex items-center justify-between py-4">
      <div class="logo">
        <a routerLink="/inicio" class="text-2xl font-bold text-primary hover:text-blue-600 transition-colors">
          BOOST AGENCY
        </a>
      </div>
      <div class="hidden lg:flex items-center space-x-8">
        <a routerLink="/inicio" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Inicio</a>
        <a routerLink="/nosotros" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Nosotros</a>
        <a routerLink="/servicios" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Servicios</a>
        <a routerLink="/planes" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Planes</a>
        <a routerLink="/fundacion" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Fundación</a>
        <a routerLink="/boostcast" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">BoostCast</a>
        <a routerLink="/tienda" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Tienda</a>
        <a routerLink="/contacto" routerLinkActive="text-primary" class="text-text-color hover:text-primary transition-colors font-medium">Contacto</a>
      </div>
      <div class="hidden lg:block">
        <a routerLink="/el-futuro-es-ahora" class="btn btn-primary">El Futuro es Ahora</a>
      </div>
      <!-- Mobile menu button -->
      <div class="lg:hidden">
        <button class="text-text-color hover:text-primary">
          <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16"></path>
          </svg>
        </button>
      </div>
    </nav>
  </header>
